mapper.select:
SELECT * FROM ( SELECT id, user_id as userId, site_code as siteCode, user_account as userAccount , vip_grade_code as vipGradeCode, next_vip_grade_code as nextVipGradeCode, bet_amount_exe as betAmountExe, finish_bet_amount as finishBetAmount, upgrade_bet_amount as upgradeBetAmount, finish_relegation_amount as finishRelegationAmount, grade_relegation_amount as gradeRelegationAmount, relegation_days as relegationDays, up_vip_time as upVipTime, relegation_days_time as relegationDaysTime, currency_code as currencyCode, created_time as createdTime, updated_time as updatedTime, creator as creator, updater as updater, ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY created_time DESC) as rn FROM user_vip_flow_record_cn
AND user_id = #{vo.userId}
AND site_code = #{vo.siteCode}
AND currency_code = #{vo.currencyCode}
) t WHERE rn = 1
AND relegationDaysTime = #{vo.relegationDaysTime} AND gradeRelegationAmount > finishRelegationAmount AND vipGradeCode != 1
AND finishBetAmount >= upgradeBetAmount AND vipGradeCode != #{vo.maxVipLevel}
AND nextVipGradeCode = #{vo.nextVipGradeCode}
AND vipGradeCode = #{vo.vipGradeCode}
AND finishRelegationAmount >= gradeRelegationAmount AND vipGradeCode = #{vo.vipMaxGradeCode}
AND relegationDaysTime = #{vo.maxGradeRelegationDaysTime} AND vipGradeCode != 1
